import React from "react";

import type {IImageComponent} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../factory";

const Image = ({ ref, ...props}: IImageComponent) => {
    const { cssProps, nativeProps } = useSeparator<IImageComponent>(props);

    function sourceToWebSrc(source?: IImageComponent['source']): string | undefined {
        if (!source) return undefined;
        if (Array.isArray(source)) return source[0]?.uri;
        if (typeof source === 'number') return undefined; // require() handled differently in bundlers
        // @ts-ignore
        return source.uri;
    }

    if(props.source){
        props.src = sourceToWebSrc(props.source)
        delete props.source
    }
    return (
        <ResponsiveElement
            nativeProps={nativeProps}
            ref={ref}
            cssProps={cssProps}
            as={"Image"}
        />
    );
}

export default Image;
